import asyncio
import time

from composio import Composio, after_execute, before_execute, schema_modifier
from composio.types import Tool

from app.config.oauth_config import get_composio_social_configs
from app.config.settings import settings
from app.constants.log_tags import LogTag
from app.core.lazy_loader import MissingKeyStrategy, lazy_provider, providers
from app.models.trigger_config import TriggerConfig

# Defensive: guarantee the Composio CustomTool monkey-patches are applied in any
# process that builds a Composio client (API, ARQ worker, future entrypoints),
# not only where an entrypoint remembers to `import app.patches`. Without the
# user_id-injection patch, custom tools 500 with "Missing user_id in
# auth_credentials".
import app.patches  # noqa: F401
from app.services.composio.custom_tools.registry import custom_tools_registry
from app.services.composio.langchain_composio_service import LangchainProvider
from app.services.composio.proxy_client import invalidate_connected_account_cache
from app.services.mcp.mcp_tools_store import get_mcp_tools_store
from app.utils.composio_hooks.registry import (
    master_after_execute_hook,
    master_before_execute_hook,
    master_schema_modifier,
)
from app.utils.query_utils import add_query_param
from shared.py.wide_events import log

COMPOSIO_SOCIAL_CONFIGS = get_composio_social_configs()


class ComposioService:
    def __init__(self, api_key: str):
        from app.config.oauth_config import OAUTH_INTEGRATIONS

        toolkit_versions: dict[str, str] = {}
        for integration in OAUTH_INTEGRATIONS:
            if integration.composio_config and integration.composio_config.toolkit_version:
                toolkit_name = integration.composio_config.toolkit.lower()
                toolkit_versions[toolkit_name] = integration.composio_config.toolkit_version

        self.composio = Composio(
            provider=LangchainProvider(),
            api_key=api_key,
            timeout=120,
            toolkit_versions=toolkit_versions or None,
        )
        custom_tools_registry.initialize(self.composio)

    async def connect_account(
        self, provider: str, user_id: str, state_token: str | None = None
    ) -> dict:
        if provider not in COMPOSIO_SOCIAL_CONFIGS:
            raise ValueError(f"Provider '{provider}' not supported")

        config = COMPOSIO_SOCIAL_CONFIGS[provider]

        log.set(composio_provider=provider, composio_user_id=user_id)
        try:
            callback_url = (
                add_query_param(
                    settings.COMPOSIO_REDIRECT_URI,
                    "state",
                    state_token,
                )
                if state_token
                else settings.COMPOSIO_REDIRECT_URI
            )

            loop = asyncio.get_event_loop()
            connection_request = await loop.run_in_executor(
                None,
                lambda: self.composio.connected_accounts.initiate(
                    user_id=user_id,
                    auth_config_id=config.auth_config_id,
                    callback_url=callback_url,
                    allow_multiple=True,
                ),
            )

            return {
                "status": "pending",
                "redirect_url": connection_request.redirect_url,
                "connection_id": connection_request.id,
            }
        except Exception as e:
            log.error(f"{LogTag.COMPOSIO} Error connecting {provider} for {user_id}: {e}")
            raise

    async def get_tools(self, tool_kit: str, exclude_tools: list[str] | None = None):
        """Get tools for a toolkit with unified master hooks."""
        log.set(composio_toolkit=tool_kit)
        log.info(f"{LogTag.COMPOSIO} Loading {tool_kit} toolkit...")

        tools = await asyncio.to_thread(
            lambda: self.composio.tools.get(  # type: ignore[call-overload]
                user_id="",
                toolkits=[tool_kit],
                limit=1000,
            )
        )

        exclude_tools = exclude_tools or []
        tool_names = [t.name for t in tools]

        custom_tool_names = custom_tools_registry.get_tool_names(tool_kit)
        for custom_tool_name in custom_tool_names:
            if custom_tool_name not in tool_names:
                tool_names.append(custom_tool_name)
        master_before_modifier = before_execute(tools=tool_names)(master_before_execute_hook)
        master_after_modifier = after_execute(tools=tool_names)(master_after_execute_hook)
        master_schema_mod = schema_modifier(tools=tool_names)(master_schema_modifier)

        tools = await asyncio.to_thread(
            lambda: self.composio.tools.get(  # type: ignore[call-overload]
                user_id="",
                toolkits=[tool_kit],
                modifiers=[
                    master_schema_mod,
                    master_before_modifier,
                    master_after_modifier,
                ],
                limit=1000,
            )
        )

        if custom_tool_names:
            custom_tools = await self.get_tools_by_name(custom_tool_names)
            seen_names = {tool.name for tool in tools}
            for tool in custom_tools:
                if tool.name in seen_names:
                    continue
                tools.append(tool)
                seen_names.add(tool.name)

        result = [tool for tool in tools if tool.name not in exclude_tools]
        await self._store_tool_metadata(tool_kit, result)
        existing = log.get().get("composio", {})
        log.set(
            composio={
                **existing,
                "toolkits": existing.get("toolkits", []) + [tool_kit],
                "tools_loaded": existing.get("tools_loaded", 0) + len(result),
            }
        )
        return result

    async def _store_tool_metadata(self, toolkit_name: str, tools: list) -> None:
        """Store Composio tool metadata in MongoDB for frontend visibility."""
        if not tools:
            return

        try:
            tool_metadata = [
                {"name": t.name, "description": getattr(t, "description", "")} for t in tools
            ]

            store = get_mcp_tools_store()
            await store.store_tools(toolkit_name.lower(), tool_metadata)
            log.debug(
                f"{LogTag.COMPOSIO} Stored {len(tool_metadata)} Composio tool metadata for {toolkit_name}"
            )
        except Exception as e:
            log.warning(
                f"{LogTag.COMPOSIO} Failed to store Composio tool metadata for {toolkit_name}: {e}"
            )

    async def get_tools_by_name(
        self,
        tool_names: list[str],
        use_before_hook: bool = True,
        use_after_hook: bool = True,
        use_schema_modifier: bool = True,
    ):
        """Get specific tools by names with unified master hooks."""
        log.set(composio_tool_names=tool_names, composio_tool_count=len(tool_names))
        start_time = time.time()

        modifiers = []

        if use_schema_modifier:
            master_schema_mod = schema_modifier(tools=tool_names)(master_schema_modifier)
            modifiers.append(master_schema_mod)

        if use_before_hook:
            master_before_modifier = before_execute(tools=tool_names)(master_before_execute_hook)
            modifiers.append(master_before_modifier)

        if use_after_hook:
            master_after_modifier = after_execute(tools=tool_names)(master_after_execute_hook)
            modifiers.append(master_after_modifier)

        result = await asyncio.to_thread(
            self.composio.tools.get,
            tools=tool_names,
            user_id="",
            modifiers=modifiers,
        )

        tools_time = time.time() - start_time
        log.info(f"{LogTag.COMPOSIO} Tools loaded: {len(result)} tools in {tools_time:.3f}s")
        existing = log.get().get("composio", {})
        log.set(
            composio={
                **existing,
                "tools_loaded": existing.get("tools_loaded", 0) + len(result),
            }
        )
        return result

    async def get_raw_tools_metadata(
        self,
        tool_kit: str | None = None,
        specific_tools: list[str] | None = None,
    ) -> list[Tool]:
        """Fetch raw Composio tool definitions WITHOUT wrapping them.

        ``get_tools``/``get_tools_by_name`` run the LangchainProvider, which
        builds a Pydantic args-model + closure per tool (~100KB each). Wrapping
        the whole ~1.6k-tool catalog this way is the dominant source of resident
        memory. For warmup we only need metadata (name + description) to index
        the catalog into ChromaDB (retrieval) and Mongo (the /tools listing).
        The raw endpoint returns ``composio.types.Tool`` objects (slug,
        description, input_parameters) with no wrapping. Executable
        StructuredTools are materialized lazily, per provider, when a subagent is
        first created (see ``ToolRegistry.register_provider_tools``).
        """

        def _fetch():
            if specific_tools:
                return self.composio.tools.get_raw_composio_tools(tools=specific_tools)
            return self.composio.tools.get_raw_composio_tools(toolkits=[tool_kit], limit=1000)

        return await asyncio.to_thread(_fetch)

    def get_tool(
        self,
        tool_name: str,
        use_before_hook: bool = True,
        use_after_hook: bool = True,
        use_schema_modifier: bool = True,
        user_id: str = "",
    ):
        """Get a specific tool by name with configurable hooks."""
        try:
            modifiers = []

            if use_schema_modifier:
                master_schema_mod = schema_modifier(tools=[tool_name])(master_schema_modifier)
                modifiers.append(master_schema_mod)

            if use_before_hook:
                master_before_modifier = before_execute(tools=[tool_name])(
                    master_before_execute_hook
                )
                modifiers.append(master_before_modifier)

            if use_after_hook:
                master_after_modifier = after_execute(tools=[tool_name])(master_after_execute_hook)
                modifiers.append(master_after_modifier)

            tools = self.composio.tools.get(
                user_id=user_id,
                tools=[tool_name],
                modifiers=modifiers,
            )

            return tools[0] if tools else None
        except Exception as e:
            log.error(f"{LogTag.COMPOSIO} Error getting tool {tool_name}: {e}")
            return None

    async def check_connection_status(self, providers: list[str], user_id: str) -> dict[str, bool]:
        """Check if a user has active connections for given providers."""
        log.set(composio_user_id=user_id, composio_providers=providers)
        result = {}
        required_auth_config_ids = []

        for provider in providers:
            result[provider] = False
            if provider in COMPOSIO_SOCIAL_CONFIGS:
                required_auth_config_ids.append(COMPOSIO_SOCIAL_CONFIGS[provider].auth_config_id)

        try:
            loop = asyncio.get_event_loop()
            user_accounts = await loop.run_in_executor(
                None,
                lambda: self.composio.connected_accounts.list(
                    user_ids=[user_id],
                    auth_config_ids=required_auth_config_ids,
                    limit=len(required_auth_config_ids),
                ),
            )

            auth_config_provider_map = {}
            for provider in providers:
                if provider in COMPOSIO_SOCIAL_CONFIGS:
                    auth_config_id = COMPOSIO_SOCIAL_CONFIGS[provider].auth_config_id
                    auth_config_provider_map[auth_config_id] = provider

            for account in user_accounts.items:
                if not account.auth_config.is_disabled and account.status == "ACTIVE":
                    account_auth_config_id = account.auth_config.id
                    if account_auth_config_id in auth_config_provider_map:
                        result[auth_config_provider_map[account_auth_config_id]] = True

            return result

        except Exception as e:
            log.error(
                f"{LogTag.COMPOSIO} Error checking connection status for providers {providers} and user {user_id}: {e}"
            )
            return result

    def get_connected_account_by_id(self, connected_account_id: str):
        try:
            connected_account = self.composio.connected_accounts.get(
                nanoid=connected_account_id,
            )
            return connected_account
        except Exception as e:
            log.error(
                f"{LogTag.COMPOSIO} Error retrieving connected account {connected_account_id}: {e}"
            )
            return None

    async def delete_connected_account(self, user_id: str, provider: str) -> dict[str, str]:
        log.set(composio_user_id=user_id, composio_provider=provider)
        if provider not in COMPOSIO_SOCIAL_CONFIGS:
            raise ValueError(f"Provider '{provider}' not supported")

        config = COMPOSIO_SOCIAL_CONFIGS[provider]

        try:
            loop = asyncio.get_event_loop()
            user_accounts = await loop.run_in_executor(
                None,
                lambda: self.composio.connected_accounts.list(
                    user_ids=[user_id],
                    auth_config_ids=[config.auth_config_id],
                    limit=100,
                ),
            )

            active_accounts = [
                acc
                for acc in user_accounts.items
                if acc.status == "ACTIVE" and not acc.auth_config.is_disabled
            ]

            if not active_accounts:
                log.info(
                    f"{LogTag.COMPOSIO} No active connected account found for {provider} and user {user_id}, nothing to delete"
                )
                return {
                    "status": "success",
                    "message": f"No active account found for {provider} - already disconnected",
                }

            delete_tasks = []
            for account in active_accounts:

                def _delete_account(acc=account):
                    return self.composio.connected_accounts.delete(nanoid=acc.id)

                delete_tasks.append(loop.run_in_executor(None, _delete_account))

            await asyncio.gather(*delete_tasks)

            log.info(
                f"{LogTag.COMPOSIO} Deleted {len(active_accounts)} connected account(s) for {provider} and user {user_id}"
            )
            return {
                "status": "success",
                "message": f"Successfully deleted {len(active_accounts)} account(s) for {provider}",
            }

        except ValueError:
            raise
        except Exception as e:
            log.error(
                f"{LogTag.COMPOSIO} Error deleting connected account for {provider} and user {user_id}: {e}"
            )
            raise
        finally:
            # Always flush the proxy connected_account_id cache: on success the
            # cached ID is gone, on partial failure it may now be invalid, and
            # on the idempotent no-op path a previous session may have cached
            # an ID revoked outside this code path. Skipping invalidation when
            # gather() raises would leave stale IDs in memory for up to the
            # full TTL.
            if config.toolkit:
                invalidate_connected_account_cache(user_id=user_id, toolkit=config.toolkit)

    async def handle_subscribe_trigger(self, user_id: str, triggers: list[TriggerConfig]):
        """Subscribe to auto-active triggers for a user."""
        log.set(composio_user_id=user_id, composio_trigger_count=len(triggers))
        active_triggers = [t for t in triggers if t.auto_activate]

        if not active_triggers:
            log.info(f"{LogTag.COMPOSIO} No auto-active triggers to subscribe for user {user_id}")
            return []

        log.info(
            f"{LogTag.COMPOSIO} Subscribing to {len(active_triggers)} auto-active triggers for user {user_id}"
        )

        try:

            def create_trigger(trigger: TriggerConfig):
                return self.composio.triggers.create(
                    user_id=user_id,
                    slug=trigger.slug,
                    trigger_config=trigger.config,
                )

            tasks = [
                asyncio.get_event_loop().run_in_executor(None, create_trigger, trigger)
                for trigger in active_triggers
            ]

            return await asyncio.gather(*tasks)
        except Exception as e:
            log.error(f"{LogTag.COMPOSIO} Error handling subscribe trigger for {user_id}: {e}")


@lazy_provider(
    name="composio_service",
    required_keys=[settings.COMPOSIO_KEY],
    strategy=MissingKeyStrategy.WARN,
)
def init_composio_service():
    if settings.COMPOSIO_KEY is None:
        raise RuntimeError("COMPOSIO_KEY is not set in settings")
    return ComposioService(settings.COMPOSIO_KEY)


def get_composio_service() -> ComposioService:
    service = providers.get("composio_service")
    if service is None:
        raise RuntimeError("ComposioService is not available")
    return service

"""
Core registry and master hooks for Composio tool system.

This module provides the central registry and master execution hooks that handle
ALL Composio tools with built-in user_id extraction and frontend streaming.

Also provides schema modifiers for customizing tool schemas before they are
presented to agents.
"""

from collections.abc import Callable
from typing import Any, Union

from composio.types import Tool, ToolExecuteParams

from app.constants.log_tags import LogTag
from shared.py.wide_events import log


class ComposioHookRegistry:
    """
    Enhanced registry for managing before_execute, after_execute hooks,
    and schema modifiers.

    Supports conditional execution based on tool name/toolkit with a single
    master hook system that handles ALL tools.
    """

    def __init__(self) -> None:
        # Registry for before_execute hooks
        self._before_hooks: list[Callable[[str, str, ToolExecuteParams], ToolExecuteParams]] = []

        # Registry for after_execute hooks
        self._after_hooks: list[Callable[[str, str, Any], Any]] = []

        # Registry for schema modifiers
        self._schema_modifiers: list[Callable[[str, str, Tool], Tool]] = []

    def register_before_hook(
        self, hook_func: Callable[[str, str, ToolExecuteParams], ToolExecuteParams]
    ) -> None:
        """Register a before_execute hook function."""
        self._before_hooks.append(hook_func)
        log.debug(f"{LogTag.COMPOSIO} Registered before_execute hook: {hook_func.__name__}")

    def register_after_hook(self, hook_func: Callable[[str, str, Any], Any]) -> None:
        """Register an after_execute hook function."""
        self._after_hooks.append(hook_func)
        log.debug(f"{LogTag.COMPOSIO} Registered after_execute hook: {hook_func.__name__}")

    def execute_before_hooks(
        self, tool: str, toolkit: str, params: ToolExecuteParams
    ) -> ToolExecuteParams:
        """Execute all registered before_execute hooks."""
        log.set(composio_tool=tool, composio_toolkit=toolkit)
        modified_params = params
        for hook_func in self._before_hooks:
            try:
                modified_params = hook_func(tool, toolkit, modified_params)
            except Exception as e:
                log.error(
                    f"{LogTag.COMPOSIO} Error executing before_execute hook {hook_func.__name__} for {tool}: {e}"
                )
                # Continue with other hooks even if one fails
        return modified_params

    def execute_after_hooks(self, tool: str, toolkit: str, response: Any) -> Any:
        """Execute all registered after_execute hooks."""
        modified_response = response
        for hook_func in self._after_hooks:
            try:
                modified_response = hook_func(tool, toolkit, modified_response)
            except Exception as e:
                log.error(
                    f"{LogTag.COMPOSIO} Error executing after_execute hook {hook_func.__name__} for {tool}: {e}"
                )
                # Continue with other hooks even if one fails
        return modified_response

    def register_schema_modifier(self, modifier_func: Callable[[str, str, Tool], Tool]) -> None:
        """Register a schema modifier function."""
        self._schema_modifiers.append(modifier_func)
        log.debug(f"{LogTag.COMPOSIO} Registered schema_modifier: {modifier_func.__name__}")

    def execute_schema_modifiers(self, tool: str, toolkit: str, schema: Tool) -> Tool:
        """Execute all registered schema modifiers."""
        modified_schema = schema
        for modifier_func in self._schema_modifiers:
            try:
                modified_schema = modifier_func(tool, toolkit, modified_schema)
            except Exception as e:
                log.error(
                    f"{LogTag.COMPOSIO} Error executing schema_modifier {modifier_func.__name__} for {tool}: {e}"
                )
                # Continue with other modifiers even if one fails
        return modified_schema


# Global registry instance
hook_registry = ComposioHookRegistry()


def master_before_execute_hook(
    tool: str, toolkit: str, params: ToolExecuteParams
) -> ToolExecuteParams:
    """
    Master before_execute hook that handles ALL tools.

    This includes:
    1. User ID extraction from RunnableConfig metadata
    2. Frontend streaming setup
    3. All registered tool-specific hooks
    """
    return hook_registry.execute_before_hooks(tool, toolkit, params)


def master_after_execute_hook(tool: str, toolkit: str, response: Any) -> Any:
    """
    Master after_execute hook that handles ALL tools.

    This includes:
    1. All registered tool-specific output processing hooks
    2. Any global response transformations
    """
    # Execute all registered tool-specific hooks
    return hook_registry.execute_after_hooks(tool, toolkit, response)


def master_schema_modifier(tool: str, toolkit: str, schema: Tool) -> Tool:
    """
    Master schema modifier that handles ALL tools.

    This modifies tool schemas before they are presented to agents.
    Useful for:
    - Adding/modifying tool descriptions
    - Setting default values for arguments
    - Adding custom guidance to tool usage
    """
    return hook_registry.execute_schema_modifiers(tool, toolkit, schema)


def register_before_hook(
    tools: Union[str, list[str]] | None = None,
    toolkits: Union[str, list[str]] | None = None,
):
    """
    Enhanced decorator for registering before_execute hooks.

    Args:
        tools: Single tool name or list of tool names to target
        toolkits: Single toolkit name or list of toolkit names to target

    Usage:
        @register_before_hook(tools=["GMAIL_FETCH_EMAILS", "GMAIL_SEND_EMAIL"])
        def gmail_param_modifier(tool, toolkit, params):
            if tool == "GMAIL_FETCH_EMAILS":
                # Handle fetch emails params
                pass
            elif tool == "GMAIL_SEND_EMAIL":
                # Handle send email params
                pass
            return params

        @register_before_hook(toolkits="GMAIL")
        def gmail_toolkit_modifier(tool, toolkit, params):
            if toolkit == "GMAIL":
                # Handle all Gmail tools
                pass
            return params
    """

    def decorator(
        func: Callable[[str, str, ToolExecuteParams], ToolExecuteParams],
    ) -> Callable[[str, str, ToolExecuteParams], ToolExecuteParams]:
        # Normalize tools and toolkits to lists
        target_tools = []
        if tools:
            target_tools = [tools] if isinstance(tools, str) else tools

        target_toolkits = []
        if toolkits:
            target_toolkits = [toolkits] if isinstance(toolkits, str) else toolkits

        def conditional_hook(
            tool: str, toolkit: str, params: ToolExecuteParams
        ) -> ToolExecuteParams:
            # Check if this hook should run for this tool/toolkit
            should_run = False

            # If no specific tools/toolkits specified, run for all
            if not target_tools and not target_toolkits:
                should_run = True
            else:
                # Check tool match
                if target_tools and tool in target_tools:
                    should_run = True
                # Check toolkit match
                if target_toolkits and toolkit in target_toolkits:
                    should_run = True

            if should_run:
                return func(tool, toolkit, params)
            return params

        hook_registry.register_before_hook(conditional_hook)
        return func

    return decorator


def register_after_hook(
    tools: Union[str, list[str]] | None = None,
    toolkits: Union[str, list[str]] | None = None,
):
    """
    Enhanced decorator for registering after_execute hooks.

    Args:
        tools: Single tool name or list of tool names to target
        toolkits: Single toolkit name or list of toolkit names to target

    Usage:
        @register_after_hook(tools=["GMAIL_FETCH_EMAILS"])
        def gmail_output_processor(tool, toolkit, response):
            if tool == "GMAIL_FETCH_EMAILS":
                # Process Gmail fetch response
                pass
            return response

        @register_after_hook(toolkits="GMAIL")
        def gmail_toolkit_processor(tool, toolkit, response):
            if toolkit == "GMAIL":
                # Process all Gmail tool responses
                pass
            return response
    """

    def decorator(
        func: Callable[[str, str, Any], Any],
    ) -> Callable[[str, str, Any], Any]:
        # Normalize tools and toolkits to lists
        target_tools = []
        if tools:
            target_tools = [tools] if isinstance(tools, str) else tools

        target_toolkits = []
        if toolkits:
            target_toolkits = [toolkits] if isinstance(toolkits, str) else toolkits

        def conditional_hook(tool: str, toolkit: str, response: Any) -> Any:
            # Check if this hook should run for this tool/toolkit
            should_run = False

            # If no specific tools/toolkits specified, run for all
            if not target_tools and not target_toolkits:
                should_run = True
            else:
                # Check tool match
                if target_tools and tool in target_tools:
                    should_run = True
                # Check toolkit match
                if target_toolkits and toolkit in target_toolkits:
                    should_run = True

            if should_run:
                return func(tool, toolkit, response)
            return response

        hook_registry.register_after_hook(conditional_hook)
        return func

    return decorator


def register_schema_modifier(
    tools: Union[str, list[str]] | None = None,
    toolkits: Union[str, list[str]] | None = None,
):
    """
    Decorator for registering schema modifiers.

    Schema modifiers transform a tool's schema before the tool is seen by an agent.
    Useful for modifying descriptions, setting defaults, or adding custom guidance.

    Args:
        tools: Single tool name or list of tool names to target
        toolkits: Single toolkit name or list of toolkit names to target

    Usage:
        @register_schema_modifier(tools=["GMAIL_SEND_EMAIL"])
        def add_draft_guidance(tool, toolkit, schema):
            schema.description += "\\n\\nPrefer creating drafts first."
            return schema

        @register_schema_modifier(tools=["GMAIL_FETCH_EMAILS"])
        def set_fetch_defaults(tool, toolkit, schema):
            # Set default values for parameters
            props = schema.input_parameters.get("properties", {})
            if "max_results" in props:
                props["max_results"]["default"] = 10
            return schema
    """

    def decorator(
        func: Callable[[str, str, Tool], Tool],
